const fileId = $json.id || $json.fileId || '';
const rawMimeType = ($json.mimeType || '').toString();
const fileName = ($json.name || $json.fileName || 'drive-file').toString();
const mimeType = rawMimeType;
const googleDocId = mimeType === 'application/vnd.google-apps.document' ? fileId : '';
const googleDocUrl = googleDocId ? `https://docs.google.com/document/d/${googleDocId}` : '';

let route = 'unsupported';
if (mimeType === 'application/pdf') {
  route = 'pdf';
} else if (mimeType.startsWith('image/')) {
  route = 'image';
} else if (mimeType === 'application/vnd.google-apps.document') {
  route = 'google_doc';
} else if (mimeType === 'text/csv' || fileName.toLowerCase().endsWith('.csv')) {
  route = 'csv';
} else if (mimeType.startsWith('text/')) {
  route = 'text_file';
}

return [{
  json: {
    route,
    fileId,
    rawText: '',
    chatId: 'REPLACE_WITH_TELEGRAM_CHAT_ID',
    messageId: '',
    mimeType,
    fileName,
    binaryKey: '',
    googleDocUrl,
    googleDocId,
    sourceType: 'google_drive_file',
    runId: $execution.id
  }
}];

function pickLongestString(value) {
  let best = '';
  const visit = (v) => {
    if (typeof v === 'string') {
      if (v.length > best.length) best = v;
      return;
    }
    if (Array.isArray(v)) {
      for (const item of v) visit(item);
      return;
    }
    if (v && typeof v === 'object') {
      for (const key of Object.keys(v)) visit(v[key]);
    }
  };
  visit(value);
  return best;
}const content = pickLongestString($input.first().json) || JSON.stringify($input.first().json);
return [{
  json: {
    content,
    fileType: 'google_doc',
    fileName: $('Normalize Input').first().json.fileName || 'Google Doc',
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_google_doc',
    runId: $('Normalize Input').first().json.runId
  }
}];

function pickLongestString(value) {
  let best = '';
  const visit = (v) => {
    if (typeof v === 'string') {
      if (v.length > best.length) best = v;
      return;
    }
    if (Array.isArray(v)) {
      for (const item of v) visit(item);
      return;
    }
    if (v && typeof v === 'object') {
      for (const key of Object.keys(v)) visit(v[key]);
    }
  };
  visit(value);
  return best;
}const content = pickLongestString($input.first().json) || JSON.stringify($input.first().json);
return [{
  json: {
    content,
    fileType: 'pdf',
    fileName: $('Normalize Input').first().json.fileName,
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_pdf',
    runId: $('Normalize Input').first().json.runId
  }
}];

const item = $input.first();
const binaryKey = $('Normalize Input').first().json.binaryKey || Object.keys(item.binary || {})[0] || 'data';

if (!binaryKey || !item.binary || !item.binary[binaryKey]) {
  throw new Error('No binary image found on the input item.');
}

const bin = item.binary[binaryKey];
const mimeType = (bin.mimeType || 'image/jpeg').toLowerCase();

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64 = Buffer.from(buffer).toString('base64');

if (!base64) {
  throw new Error('Could not convert input image to base64.');
}

const dataUrl = `data:${mimeType};base64,${base64}`;

return [{
  json: {
    imageDataUrl: dataUrl,
    fileType: 'image',
    fileName: $('Normalize Input').first().json.fileName,
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_image',
    runId: $('Normalize Input').first().json.runId
  }
}];

const payload = {
  model: 'meta/llama-3.2-11b-vision-instruct',
  messages: [
    {
      role: 'system',
      content: 'You are an OCR extraction assistant. Extract all readable text from the image exactly as written. Return plain text only. No markdown, no bullets, no commentary, no labels, no JSON.'
    },
    {
      role: 'user',
      content: [
        {
          type: 'text',
          text: 'Extract all readable text from this image exactly as written. Preserve line breaks when possible. If no readable text is visible, return exactly: NO_TEXT_EXTRACTED'
        },
        {
          type: 'image_url',
          image_url: {
            url: $json.imageDataUrl
          }
        }
      ]
    }
  ],
  temperature: 0,
  top_p: 1,
  max_tokens: 1800,
  stream: false
};

return [{
  json: {
    nimPayload: JSON.stringify(payload),
    fileType: $json.fileType,
    fileName: $json.fileName,
    chatId: $json.chatId,
    messageId: $json.messageId,
    sourceType: $json.sourceType,
    runId: $json.runId
  }
}];

const rawContent = $json.choices?.[0]?.message?.content;

let text = '';

if (typeof rawContent === 'string') {
  text = rawContent;
} else if (Array.isArray(rawContent)) {
  text = rawContent
    .map(part => {
      if (typeof part === 'string') return part;
      if (part?.type === 'text' && typeof part.text === 'string') return part.text;
      return '';
    })
    .filter(Boolean)
    .join('\n');
}

text = (text || '')
  .replace(/```[\s\S]*?```/g, '')
  .trim();

if (!text || text === 'NO_TEXT_EXTRACTED') {
  text = 'No text extracted';
}

return [{
  json: {
    content: text,
    fileType: $('Build Image Payload').first().json.fileType,
    fileName: $('Build Image Payload').first().json.fileName,
    chatId: $('Build Image Payload').first().json.chatId,
    messageId: $('Build Image Payload').first().json.messageId,
    sourceType: $('Build Image Payload').first().json.sourceType,
    runId: $('Build Image Payload').first().json.runId
  }
}];

