}const content = pickLongestString($input.first().json) || JSON.stringify($input.first().json);
return [{
  json: {
    content,
    fileType: 'text_file',
    fileName: $('Normalize Input').first().json.fileName,
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_text_file',
    runId: $('Normalize Input').first().json.runId
  }
}];

const rows = $input.all().map(item => item.json);
const content = JSON.stringify(rows, null, 2);
return [{
  json: {
    content,
    fileType: 'csv',
    fileName: $('Normalize Input').first().json.fileName,
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_csv',
    runId: $('Normalize Input').first().json.runId
  }
}];

return [{
  json: {
    content: $('Normalize Input').first().json.rawText,
    fileType: 'raw_text',
    fileName: 'telegram-message',
    chatId: $('Normalize Input').first().json.chatId,
    messageId: $('Normalize Input').first().json.messageId,
    sourceType: 'google_drive_text',
    runId: $('Normalize Input').first().json.runId
  }
}];

const input = $input.first().json;
const rawContent = (input.content || '').toString().trim();
const trimmedContent = rawContent.slice(0, 12000);

const schema = {
  type: "object",
  properties: {
    title: { type: "string" },
    summary: { type: "string" },
    category: { type: "string" },
    language: { type: "string" },
    key_points: {
      type: "array",
      items: { type: "string" }
    },
    confidence_notes: { type: "string" }
  },
  required: ["title", "summary", "category", "language", "key_points", "confidence_notes"]
};

const system = [
  'You are a document extraction and structuring assistant.',
  'Structure the already extracted text.',
  'Return only the schema fields.',
  'No reasoning.',
  'No commentary.',
  'No <think> tags.',
  'No markdown fences.',
  'Do not hallucinate missing facts.',
  'If unknown, use empty string or empty array.'
].join('\n');

const user = [
  `Source type: ${input.fileType}`,
  `File name: ${input.fileName}`,
  '',
  'Text to structure:',
  trimmedContent
].join('\n');

const payload = {
  model: 'nvidia/llama-3.3-nemotron-super-49b-v1.5',
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: user }
  ],
  temperature: 0,
  top_p: 1,
  max_tokens: 600,
  stream: false,
  guided_json: schema
};

return [{
  json: {
    nimPayload: JSON.stringify(payload),
    originalContent: rawContent,
    fileType: input.fileType,
    fileName: input.fileName,
    chatId: input.chatId,
    messageId: input.messageId,
    sourceType: input.sourceType,
    runId: input.runId
  }
}];

function safeParse(text) {
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch (e) {}
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (e) {}
  }
  return null;
}

const raw = $json.choices?.[0]?.message?.content?.trim() || '';
const cleanedRaw = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
const parsed = safeParse(cleanedRaw) || {};
const original = $('Build Structuring Payload').first().json.originalContent || '';

return [{
  json: {
    title: parsed.title || $('Build Structuring Payload').first().json.fileName || 'Untitled',
    summary: parsed.summary || original.slice(0, 300),
    category: parsed.category || '',
    language: parsed.language || '',
    key_points: Array.isArray(parsed.key_points) ? parsed.key_points : [],
    confidence_notes: parsed.confidence_notes || '',
    extracted_text: original,
    sourceType: $('Build Structuring Payload').first().json.sourceType,
    fileType: $('Build Structuring Payload').first().json.fileType,
    fileName: $('Build Structuring Payload').first().json.fileName,
    chatId: $('Build Structuring Payload').first().json.chatId,
    messageId: $('Build Structuring Payload').first().json.messageId,
    runId: $('Build Structuring Payload').first().json.runId
  }
}];

let text = [
  'FILE PROCESSED',
  '',
  `Name: ${$json.fileName || ''}`,
  `Type: ${$json.fileType || ''}`,
  `Title: ${$json.title || ''}`,
  `Category: ${$json.category || ''}`,
  '',
  'Status: Extracted and logged to Google Sheets.'
].filter(Boolean).join('\n');

if (text.length > 3500) {
  text = text.slice(0, 3490) + '\n…';
}

return [{
  json: {
    replyText: text,
    chatId: $json.chatId,
    messageId: ''
  }
}];
